const RANGES = {
  soil_moisture: [0, 100], air_humidity: [0, 100],
  soil_temperature: [-10, 60], air_temperature: [-10, 60],
  luminosity: [0, 150000],
  soil_nitrogen: [0, 2000], soil_phosphorus: [0, 2000], soil_potassium: [0, 2000],
  ph: [0, 14], conductivity: [0, 20],
};
const FIELDS = Object.keys(RANGES);

return $input.all().map(item => {
  const d = item.json;
  const payload = typeof d.raw_payload === 'string' ? JSON.parse(d.raw_payload) : (d.raw_payload || {});
  const clean = {};
  let outlierReason = null;
  for (const f of FIELDS) {
    let v = payload[f];
    if (v === undefined || v === null || v === '') { clean[f] = null; continue; }
    v = Number(v);
    if (Number.isNaN(v)) {
      clean[f] = null;
      outlierReason = (outlierReason ? outlierReason + '; ' : '') + `${f} non numérique`;
      continue;
    }
    const [lo, hi] = RANGES[f];
    if (v < lo || v > hi) {
      outlierReason = (outlierReason ? outlierReason + '; ' : '') + `${f}=${v} hors plage [${lo},${hi}]`;
    }
    clean[f] = v;
  }
  const readingTs = payload.timestamp || new Date().toISOString();
  return {
    json: {
      bronze_id: d.bronze_id,
      device_id: d.device_id,
      plot_id: d.plot_id,
      farm_id: d.farm_id,
      owner_id: d.owner_id,
      ...clean,
      reading_ts: readingTs,
      is_outlier: outlierReason !== null,
      outlier_reason: outlierReason,
      source: d.source,
    }
  };
});
